  ('rgn_mesopotamia', '메소포타미아', '티그리스·유프라테스 평원 + 시날 평지. 에덴 동산(전통적 위치)·바벨탑·우르·하란·바벨론·그발 강.', '📍', null, 33.5, 44.0, '[[36.5972, 41.7886], [37.3719, 42.7746], [37.3019, 44.1145], [36.978, 44.2818], [37.1653, 44.731], [36.0153, 45.3616], [35.7732, 46.2734], [35.6081, 45.995], [35.1276, 46.1338], [34.5816, 45.5008], [34.2155, 45.5428], [33.9708, 45.3971], [33.4157, 46.0199], [32.9577, 46.1128], [32.4237, 47.3713], [31.7944, 47.83], [31.0024, 47.6795], [30.9898, 48.0106], [30.4656, 48.0149], [29.9624, 48.5465], [30.0415, 47.2232], [29.0962, 46.5314], [29.1936, 44.7165], [31.0804, 42.0744], [31.939, 40.3693], [32.1245, 39.1454], [32.2438, 39.2928], [32.3057, 39.0414], [33.3722, 38.7735], [34.4291, 40.987], [34.769, 41.1947], [35.6404, 41.3541], [36.3834, 41.296], [36.5972, 41.7886]]'::jsonb, 'region', null, null, 100, '{"era_primeval","era_patriarch","era_monarchy","era_exile_return"}'::text[], '{}'::text[]),
  ('rgn_ararat', '아라랏 산지', '동부 아나톨리아 산악. 노아 방주가 머문 곳.', '📍', null, 39.7, 44.3, '[[39.7465, 44.7338], [40.0404, 44.2893], [40.0141, 44.0054], [40.1264, 43.6662], [40.1665, 43.7099], [40.4824, 43.5693], [40.7195, 43.7227], [41.0, 43.5273], [41.0, 45.3817], [40.9122, 45.5], [40.7611, 45.5], [40.6381, 45.3762], [40.4866, 45.5], [39.51, 45.5], [39.5706, 45.1726], [39.7651, 45.0316], [39.7465, 44.7338]]'::jsonb, 'region', null, null, 80, '{"era_primeval"}'::text[], '{}'::text[]),
  ('rgn_aram_naharaim', '밧단아람', '메소포타미아 북부 (시리아 동북). 하란을 포함한 야곱-라반 시절의 주요 무대.', '📍', null, 36.86, 39.04, '[[36.5331, 41.5], [36.2725, 41.2618], [35.7246, 41.3594], [35.0, 41.1996], [35.0, 38.5], [37.5, 38.5], [37.5, 41.5], [36.5331, 41.5]]'::jsonb, 'region', null, null, 80, '{"era_patriarch"}'::text[], '{}'::text[]),
  ('rgn_assyria', '앗수르', '티그리스 상류 지역. 니느웨를 수도로 한 신앗수르 제국 본토. 요나·이사야 시대 침공자.', '📍', null, 36.36, 43.15, '[[36.5972, 41.7886], [37.3719, 42.7746], [37.2272, 43.6758], [37.3019, 44.1145], [36.978, 44.2818], [37.176, 44.606], [37.1424, 44.7651], [34.5, 44.8], [34.5, 41.5], [36.5331, 41.5], [36.5972, 41.7886]]'::jsonb, 'region', null, null, 90, '{"era_monarchy"}'::text[], '{}'::text[]),
