  ('rgn_egypt', '애굽', '나일강 하류 비옥한 델타 + 나일강 본류. 고센 땅·애굽 궁정·요셉의 사역지·출애굽 출발지·아기 예수 피난·예레미야 도피.', '📍', null, 30.5, 31.2, '[[22.0, 31.436], [22.2024, 31.4003], [22.0, 31.2447], [22.0, 24.9803], [29.1819, 24.9803], [30.2011, 24.7032], [30.6785, 24.9614], [31.3348, 24.8527], [31.655, 25.1505], [31.5128, 25.3822], [31.6209, 25.8933], [31.3779, 27.248], [30.8303, 29.0721], [31.2584, 30.2227], [31.4576, 30.3951], [31.5668, 30.9235], [31.417, 30.563], [31.4628, 31.0018], [31.6033, 31.0829], [31.4583, 31.5244], [31.5414, 31.889], [31.3411, 32.136], [31.4825, 31.8922], [31.2926, 31.7711], [31.0928, 32.1018], [31.2009, 32.2818], [31.2937, 32.2162], [31.1993, 32.4], [22.0, 32.4], [22.0, 31.436]]'::jsonb, 'region', null, null, 100, '{"era_patriarch","era_exodus","era_monarchy","era_exile_return","era_nt_public_ministry"}'::text[], '{}'::text[]),
  ('rgn_red_sea', '홍해 (갈대 바다)', '수에즈만 좁은 해협. 출애굽 시 바다가 갈라진 곳.', '📍', null, 28.5, 32.95, '[[30.0, 32.4], [29.5, 32.55], [29.0, 32.75], [28.5, 32.95], [28.0, 33.1], [27.6, 33.2], [27.3, 33.2], [27.1, 33.05], [27.1, 32.85], [27.3, 32.65], [27.7, 32.5], [28.2, 32.45], [28.8, 32.42], [29.5, 32.4]]'::jsonb, 'region', null, null, 90, '{"era_exodus"}'::text[], '{}'::text[]),
  ('rgn_sinai_peninsula', '시나이 반도', '시나이 반도 + 미디안 사막(요단 동남). 시내산·호렙·르비딤·마라·신 광야·미디안 도피지.', '📍', null, 28.54, 33.97, '[[31.074, 32.6846], [31.1682, 33.1299], [31.0845, 33.1943], [31.1304, 33.6665], [31.2923, 34.2125], [29.4773, 34.9043], [29.2706, 34.7364], [28.016, 34.3997], [27.7643, 34.2201], [28.0477, 33.7603], [28.5677, 33.2478], [28.9783, 33.1302], [29.5218, 32.7215], [29.974, 32.5657], [29.7284, 32.4], [31.1993, 32.4], [31.074, 32.6846]]'::jsonb, 'region', null, null, 100, '{"era_exodus","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_negev', '네게브·아라바', '유다 남쪽 사막 + 아라바 협곡. 브엘세바·그랄·가데스바네아.', '📍', null, 30.95, 34.85, '[[31.3187, 34.2], [31.4, 34.289], [31.4, 35.4363], [31.1324, 35.4393], [30.5, 35.1663], [30.5, 34.5192], [31.3187, 34.2]]'::jsonb, 'region', null, null, 80, '{"era_patriarch","era_exodus","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_idumea', '에돔', '사해 남쪽 ~ 아카바 만 사이의 산지. 에돔 산지·세일·페트라.', '📍', null, 30.32, 35.46, '[[29.5, 35.0], [30.4209, 35.1406], [30.95, 35.3664], [30.95, 36.0], [29.5, 36.0], [29.5, 35.0]]'::jsonb, 'region', null, null, 70, '{"era_patriarch","era_exodus","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_philistia', '블레셋 평원', '지중해 동안 평원의 블레셋 5도성: 가사·아스돗·아스글론·가드·에그론.', '📍', null, 31.6, 34.65, '[[31.3187, 34.2], [31.5923, 34.484], [32.0, 34.7219], [32.0, 34.95], [31.2, 34.95], [31.2, 34.2486], [31.3187, 34.2]]'::jsonb, 'region', null, null, 80, '{"era_judges","era_monarchy","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_judea', '유대', '유다 산지 + 베냐민 + 사해 권역 + 유대 광야. 예루살렘·베들레헴·헤브론·여리고·사해. 사사 유다지파부터 신약 로마 속주까지 통합.', '📍', null, 31.55, 35.25, '[[30.95, 35.55], [30.95, 35.4], [31.0276, 35.4], [30.95, 35.3664], [30.95, 34.95], [32.1, 34.95], [32.1, 35.55], [30.95, 35.55]]'::jsonb, 'region', null, null, 100, '{"era_patriarch","era_judges","era_monarchy","era_exile_return","era_nt_public_ministry","era_nt_apostolic","era_nt_post_apostolic"}'::text[], '{}'::text[]),
  ('rgn_samaria', '사마리아', '에브라임 산지 + 므낫세 일부. 세겜·실로·벧엘·도단·사마리아 성. 사사 에브라임부터 분열왕국 북이스라엘 수도, 신약 사마리아까지 통합.', '📍', null, 32.4, 35.25, '[[32.1, 35.55], [32.1, 34.95], [32.65, 34.95], [32.65, 35.55], [32.1, 35.55]]'::jsonb, 'region', null, null, 90, '{"era_patriarch","era_judges","era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_galilee', '갈릴리·이스르엘', '갈릴리 호수 + 갈릴리 산지 + 이스르엘 평원 + 갈멜 + 헤르몬 남쪽. 가버나움·나사렛·가나·므깃도·다볼·길보아·세사라빌립보.', '📍', null, 32.95, 35.3, '[[32.65, 34.9361], [33.0837, 35.1086], [33.0757, 35.4112], [33.1195, 35.4932], [33.2505, 35.5325], [33.2406, 35.6029], [33.4157, 35.8407], [33.2911, 35.785], [32.9444, 35.888], [32.7349, 35.7873], [32.65, 35.5801], [32.65, 34.9361]]'::jsonb, 'region', null, null, 100, '{"era_judges","era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_coastal_plain', '해안 평원 (사론)', '지중해 동안 사론 평원. 가이사랴(해변)·욥바·룻다·아리마대.', '📍', null, 32.3, 34.75, '[[32.0, 34.7219], [32.6141, 34.9219], [32.65, 34.95], [32.0, 34.95], [32.0, 34.7219]]'::jsonb, 'region', null, null, 80, '{"era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_moab', '모압', '사해 동편 고원. 모압 평지(가나안 입성 직전)·룻의 고향·발람.', '📍', null, 31.55, 35.72, '[[30.95, 35.55], [31.5, 35.55], [31.5, 36.2], [30.95, 36.2], [30.95, 35.55]]'::jsonb, 'region', null, null, 70, '{"era_exodus","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_ammon', '암몬', '요단 동편 북부. 랍바암몬(현 암만). 입다·다윗 시대 적국.', '📍', null, 31.95, 35.93, '[[32.3869, 36.3721], [31.5, 36.4], [31.5, 35.85], [32.4, 35.85], [32.3869, 36.3721]]'::jsonb, 'region', null, null, 70, '{"era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_gilead', '길르앗', '요단 동편 중부. 얍복강·라못길르앗·얍베스길르앗·미스바 길르앗. 야곱 라반 추격, 입다, 엘리야의 고향.', '📍', null, 32.3, 35.85, '[[32.5338, 36.0595], [32.4448, 36.3], [32.1, 36.3], [32.1, 35.55], [32.65, 35.5801], [32.65, 35.9694], [32.5338, 36.0595]]'::jsonb, 'region', null, null, 70, '{"era_patriarch","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_bashan', '바산', '요단 동편 북단 고원. 바산 옥 왕·헤르몬 남쪽 평원. 골란 일대.', '📍', null, 32.95, 36.1, '[[32.65, 35.5801], [32.7349, 35.7873], [32.9444, 35.888], [33.2911, 35.785], [33.4, 35.8336], [33.4, 36.55], [32.65, 36.55], [32.65, 35.5801]]'::jsonb, 'region', null, null, 60, '{"era_exodus","era_judges","era_monarchy"}'::text[], '{}'::text[]),
  ('rgn_perea', '베레아', '요단 동편 신약 시대 행정 구역. 예수의 후기 사역지·요한 침례지(요단강 동편).', '📍', null, 31.85, 35.65, '[[31.5, 35.55], [32.1, 35.55], [32.1, 35.95], [31.5, 35.95], [31.5, 35.55]]'::jsonb, 'region', null, null, 70, '{"era_nt_public_ministry"}'::text[], '{}'::text[]),
  ('rgn_decapolis', '데카폴리스', '갈릴리 동남 10개 헬라 도시 연합. 거라사·가다라·스굿도볼리.', '📍', null, 32.5, 35.85, '[[32.5338, 36.0595], [32.3802, 36.4], [32.25, 36.4], [32.25, 35.5705], [32.6409, 35.5729], [32.7349, 35.7873], [32.85, 35.8379], [32.85, 36.4], [32.65, 36.4], [32.65, 35.9694], [32.5338, 36.0595]]'::jsonb, 'region', null, null, 60, '{"era_nt_public_ministry"}'::text[], '{}'::text[]),
  ('rgn_phoenicia', '페니키아', '지중해 동안 북부 해안. 두로·시돈·사렙다·비블로스. 엘리야의 사렙다 과부, 예수의 가나안 여인, 바울 여행.', '📍', null, 33.5, 35.4, '[[33.0, 35.4], [33.0, 35.0859], [34.0322, 35.6118], [34.2482, 35.6479], [34.4374, 35.8043], [34.5, 36.0], [33.7659, 36.0], [33.6676, 35.9424], [33.5511, 36.0], [33.2406, 35.6029], [33.2505, 35.5325], [33.0, 35.4]]'::jsonb, 'region', null, null, 80, '{"era_monarchy","era_nt_public_ministry","era_nt_apostolic"}'::text[], '{}'::text[]),
  ('rgn_aram_damascus', '다메섹 아람', '다메섹을 수도로 한 시리아 남부 아람 왕국 + 신약 시리아 남부. 엘리사·바울 회심.', '📍', null, 33.51, 36.3, '[[33.0, 36.0], [33.7659, 36.0], [33.8394, 36.365], [33.9253, 36.2778], [34.2212, 36.585], [34.4324, 36.5044], [34.5, 36.3298], [34.5, 37.5], [33.0, 37.5], [33.0, 36.0]]'::jsonb, 'region', null, null, 90, '{"era_monarchy","era_nt_apostolic"}'::text[], '{}'::text[]),
